# Category: xxe

import xml.etree.ElementTree as ET

def parse_config(file):
    settings = {}

    tree = ET.parse(file)
    root = tree.getroot()

    for elem in root:
        key = elem.tag
        value = ''.join([child.text for child in elem])
        settings[key] = value

    return settings